#include <stdio.h>

// Multiply the big integer stored in digits[] (least significant digit first) by x.
void multiply(int *digits, int *size, int x) {
    int carry = 0;
    for (int i = 0; i < *size; ++i) {
        int prod = digits[i] * x + carry;
        digits[i] = prod % 10;
        carry = prod / 10;
    }
    while (carry) {
        digits[(*size)++] = carry % 10;
        carry /= 10;
    }
}

int main() {
    int T, N;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d", &N);
        int digits[200]; // enough for 100!
        int size = 1;
        digits[0] = 1; // start with 1
        int i = N;
        do {
            multiply(digits, &size, i);
            i--;
        } while (i > 0);
        for (int j = size - 1; j >= 0; --j) putchar('0' + digits[j]);
        putchar('\n');
    }
    return 0;
}

